-- ═══════════════════════════════════════════════════════════════════
-- CodeQuest · Migración 017 — SQL con Oracle · m04: DDL en Oracle
-- ═══════════════════════════════════════════════════════════════════
-- Cubre la Parte VII (integridad: las cinco constraints, nivel
-- columna vs tabla, acciones referenciales, declarativas ANTES que
-- triggers, activar/desactivar) y la Parte X en su tramo DDL
-- (CREATE TABLE y tipos de datos, ALTER, DELETE vs TRUNCATE vs DROP,
-- vistas, secuencias y sinónimos). DDL/DML/DCL/TCL como mapa inicial.
-- Precisiones vinculantes: distinguir DDL/DML/DCL/TCL; el DDL hace
-- COMMIT IMPLÍCITO; TRUNCATE es DDL y NO se revierte con ROLLBACK;
-- las secuencias DEJAN HUECOS (unicidad sí, continuidad no);
-- constraints declarativas ANTES que triggers; UNIQUE admite nulos.
-- Práctica de editor (regex+mockOutput): DDL real de la tabla LOTES.
-- Reglas de contenido: quizzes autocontenidos o con términos técnicos.
-- OJO: SQL con Oracle está PUBLICADO — esta migración sale en vivo.
-- Idempotente: borra y recrea las lecciones de ESTE módulo.
-- Ejecutar DESPUÉS de 011 (estructura v2).
-- ═══════════════════════════════════════════════════════════════════

-- Limpia el módulo (cascade borra sus content_blocks)
delete from public.lessons
where module_id = (
  select m.id
  from public.modules m
  join public.courses c on c.id = m.course_id
  where c.slug = 'sql-oracle' and m.slug = 'm04-ddl-oracle'
);

-- ── Lecciones del módulo ──────────────────────────────────────────────
insert into public.lessons (module_id, slug, title, kind, xp, sort_order)
